-- Importar pedidos históricos de Tienda Nube
-- 129 pedidos, números 100 a 232

CREATE TABLE IF NOT EXISTS pedidos_historicos (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  numero INTEGER UNIQUE,
  cliente_nombre TEXT,
  cliente_email TEXT,
  cliente_telefono TEXT,
  ciudad TEXT,
  provincia TEXT,
  items JSONB,
  subtotal NUMERIC DEFAULT 0,
  descuento NUMERIC DEFAULT 0,
  costo_envio NUMERIC DEFAULT 0,
  total NUMERIC DEFAULT 0,
  estado TEXT DEFAULT 'completado',
  medio_pago TEXT,
  medio_envio TEXT,
  notas TEXT,
  origen TEXT DEFAULT 'tiendanube',
  created_at TIMESTAMPTZ
);

ALTER TABLE pedidos_historicos ENABLE ROW LEVEL SECURITY;
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename = 'pedidos_historicos' AND policyname = 'Solo admins') THEN
    CREATE POLICY "Solo admins" ON pedidos_historicos USING (auth.role() = 'authenticated');
  END IF;
END $$;

ON CONFLICT (numero) DO NOTHING;

-- Verificar
SELECT COUNT(*) as total_pedidos, SUM(total) as facturado_total, MIN(created_at) as primer_pedido FROM pedidos_historicos;
